import{_ as t}from"./chunks/文件受限图.DsG20F9s.js";import{_ as n,o as i,c as a,a2 as r}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Bildmoderation und Zugriffsmodus","description":"","frontmatter":{},"headers":[],"relativePath":"de-DE/Safety/image-moderation-and-access-mode.md","filePath":"de-DE/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),d={name:"de-DE/Safety/image-moderation-and-access-mode.md"};function s(l,e,o,h,u,f){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="bildmoderation-und-zugriffsmodus" tabindex="-1">Bildmoderation und Zugriffsmodus <a class="header-anchor" href="#bildmoderation-und-zugriffsmodus" aria-label="Permalink to &quot;Bildmoderation und Zugriffsmodus&quot;">​</a></h1><p>Bildmoderation und Zugriffsmodus steuern, welche Dateien Besucher sehen dürfen, basierend auf öffentlichen Regeln, Listen und Altersfreigaben.</p><p>Sie wirken zusammen mit öffentlicher Galerie, Zufallsbild-API und externem Dateizugriff.</p><h2 id="moglichkeiten" tabindex="-1">Möglichkeiten <a class="header-anchor" href="#moglichkeiten" aria-label="Permalink to &quot;Möglichkeiten&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Funktion</th><th>Beschreibung</th></tr></thead><tbody><tr><td>Bildmoderation</td><td>Inhalts- oder Einstufungsinformationen speichern</td></tr><tr><td>Blacklist</td><td>Dateien ausschließen, die nicht öffentlich sein sollen</td></tr><tr><td>Whitelist-Modus</td><td>Nur ausdrücklich erlaubte Dateien veröffentlichen</td></tr><tr><td>Alterskontrolle</td><td>Sichtbarkeit von R12, R16, R18 und ähnlichen Stufen steuern</td></tr><tr><td>Zugriffsmodus</td><td>Sichtbaren Bereich für Besucher global ändern</td></tr></tbody></table><h2 id="zugriffsmodus" tabindex="-1">Zugriffsmodus <a class="header-anchor" href="#zugriffsmodus" aria-label="Permalink to &quot;Zugriffsmodus&quot;">​</a></h2><p>Der Zugriffsmodus begrenzt, was öffentliche Seiten und die Zufallsbild-API zurückgeben dürfen.</p><p>Für eine allgemein zugängliche Seite kannst du nur unkritische Dateien ausgeben lassen. Für interne oder eingeschränkte Nutzung können Regeln flexibler gesetzt werden.</p><h2 id="eingeschrankte-datei" tabindex="-1">Eingeschränkte Datei <a class="header-anchor" href="#eingeschrankte-datei" aria-label="Permalink to &quot;Eingeschränkte Datei&quot;">​</a></h2><p>Wenn eine Datei eingeschränkt ist, sieht der Besucher einen Hinweis statt des ursprünglichen Inhalts.</p><p><img src="'+t+'" alt="Eingeschränkte Datei" loading="lazy"></p><h2 id="betriebsarten" tabindex="-1">Betriebsarten <a class="header-anchor" href="#betriebsarten" aria-label="Permalink to &quot;Betriebsarten&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Ansatz</th><th>Geeignet für</th></tr></thead><tbody><tr><td>Blacklist</td><td>Standardmäßig veröffentlichen und problematische Dateien ausschließen</td></tr><tr><td>Whitelist</td><td>Nur geprüfte und erlaubte Dateien veröffentlichen</td></tr><tr><td>Altersfreigabe</td><td>Sichtbarkeit nach Inhaltsstufe steuern</td></tr></tbody></table><p>Für öffentliche Seiten helfen Whitelist oder Altersfreigabe, ungewollte Veröffentlichungen zu vermeiden.</p><h2 id="prufpunkte" tabindex="-1">Prüfpunkte <a class="header-anchor" href="#prufpunkte" aria-label="Permalink to &quot;Prüfpunkte&quot;">​</a></h2><ol><li>Prüfe, ob die Datei in der öffentlichen Galerie erscheint.</li><li>Prüfe, ob die Zufallsbild-API keine eingeschränkten Dateien zurückgibt.</li><li>Beachte nach Listenänderungen mögliche Caches.</li><li>Bei automatischer Einstufung sensible Dateien manuell prüfen, da Modelle Fehler machen können.</li></ol>',16)])])}const b=n(d,[["render",s]]);export{g as __pageData,b as default};
